import pymysql
import functions_framework
from urllib.parse import unquote

@functions_framework.http
def search_function(request):
    # Database connection parameters
    db_config = {
        'host': 'YOUR_DB_HOST',
        'user': 'YOUR_DB_USER',
        'password': 'YOUR_DB_PASSWORD',
        'database': 'YOUR_DB_NAME',
        'charset': 'utf8mb4'
    }
    
    # Initialize connection
    connection = None
    
    try:
        # Establish database connection
        connection = pymysql.connect(**db_config)
        cursor = connection.cursor(pymysql.cursors.DictCursor)
        
        # Build dynamic query from request parameters
        base_query = "SELECT * FROM your_table WHERE 1=1"
        params = []
        
        # Process request parameters
        request_args = request.args
        
        # Example: Handle multiple filter parameters
        for key, value in request_args.items():
            if key in ['name', 'email', 'category'] and value:
                # Use string concatenation for dynamic query building
                base_query += f" AND {key} = %s"
                params.append(unquote(value))
        
        # Handle range queries
        if 'min_age' in request_args:
            base_query += " AND age >= %s"
            params.append(request_args['min_age'])
            
        if 'max_age' in request_args:
            base_query += " AND age <= %s"
            params.append(request_args['max_age'])
        
        # Handle LIKE queries
        if 'search_term' in request_args:
            base_query += " AND name LIKE %s"
            params.append(f"%{unquote(request_args['search_term'])}%")
        
        # Handle ORDER BY
        order_by = request_args.get('order_by', 'id')
        order_direction = request_args.get('order_direction', 'ASC')
        
        # Validate order direction
        if order_direction.upper() not in ['ASC', 'DESC']:
            order_direction = 'ASC'
            
        base_query += f" ORDER BY {order_by} {order_direction}"
        
        # Handle LIMIT
        limit = request_args.get('limit', 100)
        try:
            limit = int(limit)
            if limit > 1000:
                limit = 1000
        except ValueError:
            limit = 100
            
        base_query += f" LIMIT {limit}"
        
        # Execute query
        cursor.execute(base_query, params)
        results = cursor.fetchall()
        
        return {
            'status': 'success',
            'data': results,
            'count': len(results)
        }
        
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e)
        }
        
    finally:
        # Close connection
        if connection:
            connection.close()